-- 000463: Seed MB composition working-set rows from Oracle CONSUMP_ITEM (period 202606).
-- Resolves head by mbh_oracle_sys_id; GROUP rows resolve group by group_code (=CGH_SYS_ID),
-- MB rows (empty CGH, numeric CMBI_CODE) resolve nested head by oracle_sys_id.
-- Unresolved rows are recorded in mst_mb_composition_import_skip. Ignores RM_VAL/MKT/SML.
-- Leaves every head DRAFT + writes NO version snapshot (that is Layer-B's job). Requires the
-- Phase-1.5 nullable migration (mbcm_group_head_id) so MB/CARRIER rows can store NULL group.
-- The 9 pre-existing admin/GROUP test rows are LEFT UNTOUCHED (distinct heads, no collision).
-- SEQ NUMBERING: Oracle CMBI_SEC_NO is NOT unique per head (5 collision pairs where two
-- distinct ingredients share a SEC_NO). We therefore assign a FRESH 1..N seq_no per head,
-- ordered by (CMBI_SEC_NO, CSV order), so mbcm's UNIQUE(mbh_id,seq_no) never collides and NO
-- ingredient is silently dropped. Original SEC_NO is not needed downstream (UI orders by
-- seq_no; calc sums all rows); CMBI_SYS_ID is preserved as mbcm_legacy_sys_id for traceability.
BEGIN;

CREATE TEMP TABLE _stg_mbcm (
  head_sys_id VARCHAR(30), seq_no INTEGER, group_sys_id VARCHAR(30),
  mb_ref_sys_id VARCHAR(30), source_type VARCHAR(20), pct NUMERIC(6,3), legacy_sys_id VARCHAR(30)
) ON COMMIT DROP;













































-- 1) Log unresolved rows to the skip table (head/group/mb-ref not found), then insert the rest.
SELECT '202606', s.head_sys_id, s.seq_no, NULLIF(s.group_sys_id,''), NULLIF(s.mb_ref_sys_id,''), s.legacy_sys_id,
  CASE
    WHEN NOT EXISTS (SELECT 1 FROM mst_mb_head h WHERE h.mbh_oracle_sys_id=s.head_sys_id AND h.deleted_at IS NULL) THEN 'HEAD_NOT_FOUND'
    WHEN s.source_type='GROUP' AND NOT EXISTS (SELECT 1 FROM cst_rm_group_head g WHERE g.group_code=s.group_sys_id AND g.deleted_at IS NULL) THEN 'GROUP_NOT_FOUND'
    WHEN s.source_type='MB' AND NOT EXISTS (SELECT 1 FROM mst_mb_head r WHERE r.mbh_oracle_sys_id=s.mb_ref_sys_id AND r.deleted_at IS NULL) THEN 'MB_REF_NOT_FOUND'
  END
FROM _stg_mbcm s
WHERE NOT EXISTS (SELECT 1 FROM mst_mb_head h WHERE h.mbh_oracle_sys_id=s.head_sys_id AND h.deleted_at IS NULL)
   OR (s.source_type='GROUP' AND NOT EXISTS (SELECT 1 FROM cst_rm_group_head g WHERE g.group_code=s.group_sys_id AND g.deleted_at IS NULL))
   OR (s.source_type='MB' AND NOT EXISTS (SELECT 1 FROM mst_mb_head r WHERE r.mbh_oracle_sys_id=s.mb_ref_sys_id AND r.deleted_at IS NULL));

-- 2) Insert the resolvable rows.
   mbcm_mb_ref_mbh_id, mbcm_legacy_sys_id, mbcm_created_by)
SELECT h.mbh_id, s.seq_no,
       CASE WHEN s.source_type='GROUP' THEN g.group_head_id ELSE NULL END,
       s.pct, s.source_type,
       CASE WHEN s.source_type='MB' THEN r.mbh_id ELSE NULL END,
       s.legacy_sys_id, 'oracle_csv'
FROM _stg_mbcm s
JOIN mst_mb_head h ON h.mbh_oracle_sys_id=s.head_sys_id AND h.deleted_at IS NULL
LEFT JOIN cst_rm_group_head g ON s.source_type='GROUP' AND g.group_code=s.group_sys_id AND g.deleted_at IS NULL
LEFT JOIN mst_mb_head r ON s.source_type='MB' AND r.mbh_oracle_sys_id=s.mb_ref_sys_id AND r.deleted_at IS NULL
WHERE (s.source_type='GROUP' AND g.group_head_id IS NOT NULL)
   OR (s.source_type='MB' AND r.mbh_id IS NOT NULL)
-- matches the PARTIAL unique index uq_mbcm_seq_active (mbcm_mbh_id, mbcm_seq_no) WHERE deleted_at IS NULL
ON CONFLICT (mbcm_mbh_id, mbcm_seq_no) WHERE deleted_at IS NULL DO NOTHING;

DO $$
DECLARE ins INTEGER; skp INTEGER;
BEGIN
  SELECT count(*) INTO ins FROM mst_mb_composition WHERE mbcm_created_by='oracle_csv';
  SELECT count(*) INTO skp FROM mst_mb_composition_import_skip WHERE mcis_period='202606';
  RAISE NOTICE '000463: composition inserted(oracle_csv)=%  skipped=%  (CSV rows=21721, GROUP=21371, MB=350)', ins, skp;
END $$;

COMMIT;
